 32→    {
 33→        $this->service = app(ResumeService::class);
 34→    }
 35→
 36→    /**
 37→     * 根据条件搜索.
 38→     *
 39→     * @param Request $request
 40→     * @return JsonResponse
 41→     */
 42→    public function search(Request $request)
 43→    {
 44→        $input = Arr::only($request->all(), [ // 读取查询数据
 45→            'channel_ids', 'username_hash_filter', 'job_ids', 'gender_hash_filter', 'status', 'inputer_user_id',
 46→            'inputer_user_ids', 'recent_apply_job_ids', 'age_lower', 'age_upper', 'experience', 'per_page',
 47→            'mark', 'label_ids', 'regions', 'countries', 'nickname_hash_filter', 'graduate_experience', 'graduate_experience_replace_filter', // 后续考虑再添加
 48→            'username_replace_filter', 'mobile_num_hash_filter', 'email_hash_filter', 'nickname_replace_filter', 'graduate_year_hash_filter',
 49→            'enable_search_optimization', // 设置为 true 表示开启搜索优化，采用新的子查询策略
 50→            'next_replace_filter',  // 是否使用新的 replace 搜索缓存
 51→        ]) + ['per_page' => 50];
 52→        $searchlist = $this->service->getsearchlist($input); // 获取查询结果
 53→        return $this->responseJsonSuccess($searchlist); // 输出
 54→    }
 55→
 56→    /**
 57→     * 更新简历.
 58→     *
 59→     * @param Request $request
 60→     * @return JsonResponse
 61→     */
 62→    public function update(Request $request)
 63→    {
 64→        $input = $this->service->fillParams($request->all()['resume']);
 65→
 66→        // 因为是增量更新，所以需要取原始简历的其他字段
 67→        $old_info = ResumeMd::find($input['id'])->toArray();
 68→        $resume_info = $input + $old_info;
 69→        [$_, $repeat] = $this->service->existDuplication($resume_info);
 70→        if (!empty($repeat) && !$request->is_force) { // 如果这个简历重复，且不强制覆盖的话
 71→            return $this->responseJsonSuccess([
 72→                'flag' => 'repeat',
 73→                'resume_info' => $repeat,
 74→            ]);
 75→        }
 76→        $suspect = $this->service->suspectDuplication($resume_info);
 77→        if (!empty($suspect) && !$request->is_force) { // 如果简历不重复，但是存在疑似简历，且无强制
 78→            // 返回疑似数组
 79→            return $this->responseJsonSuccess([
 80→                'flag' => 'suspect',
 81→                'resume_info' => $suspect,
 82→            ]);
 83→        }
 84→
 85→        if (!$this->service->coverResumePermission($input['id'])) {
 86→            return $this->responseJsonFail(__('my_api.no_permission_update_resume'), 843);
 87→        }
 88→        $checkFrequentService = app(\App\Service\FrequentOperationService::class);
 89→        $checkFrequentService->checkUpdateResume($input['id']);
 90→        if (!empty($old_info) && !empty($input['expect_job_ids'])) {
 91→            if (!in_array($input['expect_job_ids'][0][2], array_column($old_info['expect_job_ids'] ?? [], 2))) {
 92→                $input['expect_job_ids'] = array_values(array_unique(array_merge($old_info['expect_job_ids'] ?? [], $input['expect_job_ids']), SORT_REGULAR));
 93→            } else {
 94→                // 有重复投递的岗位, 重复投递岗位申请时间修改成最新的投递时间, 20221202
 95→                $tmp = $old_info['expect_job_ids'];
 96→                foreach ($tmp as $k => $v) {
 97→                    if ($v[2] == $input['expect_job_ids'][0][2] && count($v) > 3 && count($input['expect_job_ids'][0]) > 3) {
 98→                        $tmp[$k][3] = $input['expect_job_ids'][0][3];
 99→                    }
100→                }
101→                $input['expect_job_ids'] = $tmp;
102→            }
103→        }
104→        if (isset($input['expect_job_ids']) && !empty($input['expect_job_ids'])) {
105→            $input['recent_apply_time'] = date('Y-m-d H:i:s');
106→        }
107→
108→        // FIX: https://jira.xinyoudi.com/browse/XINXI-6829
109→        // inputer_user_id 位于外侧，上面的 fillParams 不会使用前端传递的 inputer_user_id
110→        if ($request->has('inputer_user_id') && !empty($request->input('inputer_user_id'))) {
111→            $input['inputer_user_id'] = $request->input('inputer_user_id');
112→        }
113→
114→        $this->service->updateResume($input, 'not_online', 'not_auto');
115→        $checkFrequentService->recordUpdateResume($input['id']);
116→        return $this->responseJsonSuccess([]);
117→    }
