362→    public function introduceResumes(Request $request)
363→    {
364→        $sfuser = $request->input('sfuser_info');
365→        $recIds = RecruitmentProcessionMd::alias('rp')
366→            ->join('introduce_resumes as ir', 'rp.resume_id', 'ir.resume_id')
367→            ->join('sfusers as si', 'si.id', '=', 'ir.sfuser_id')
368→            ->join('resumes as re', 're.id', '=', 'ir.resume_id')
369→            ->where('si.id', $sfuser['id'])
370→            ->whereIn('ir.status', ['success', 'repeat'])
371→            ->groupBy('ir.resume_id')
372→            ->selectRaw('max(rp.id) as max_id, ir.resume_id,ir.is_cooperation as is_cooperation, ir.username, ir.sub_code,re.inputer_user_id ,ir.status, ir.created_at');
373→
374→        $subQuery = RecruitmentProcessionMd::fromSub($recIds, 'rec')
375→            ->join('recruitment_procession as rp', 'rp.id', '=', 'rec.max_id')
376→            ->leftJoin('resume_filter as rf_ini', function ($join) {
377→                $join->on('rf_ini.rec_pro_id', '=', 'rp.id')
378→                    ->where('rf_ini.round_times', 1);
379→            })
380→            ->leftJoin('resume_filter as rf_re', function ($join) {
381→                $join->on('rf_re.rec_pro_id', '=', 'rp.id')
382→                    ->where('rf_re.round_times', 2);
383→            })
384→            ->leftJoin('interview_records as ir', function ($join) {
385→                $join->on('ir.rec_pro_id', '=', 'rp.id')
386→                    ->where('ir.round_times', 1);
387→            })
388→            ->leftJoin('offer_approval as oa', 'oa.rec_pro_id', '=', 'rp.id')
389→            ->leftJoin('waiting_entry as we', 'we.rec_pro_id', '=', 'rp.id')
390→            ->leftJoin('staff_information as si', 'rec.resume_id', '=', 'si.resume_id')
391→            ->groupBy('rp.id')
392→            ->selectRaw("rec.resume_id ,rec.created_at , rec.username,
393→            if(si.status = 'in_service', 'in_service',rp.status) as rec_status,
394→            date(min(rf_ini.created_at)) as ini_scr, date(min(rf_re.created_at)) as re_scr,
395→            date(min(ir.created_at)) as interview, date(min(oa.created_at)) as offer_pro,
396→            date(min(we.created_at)) as wait_entry, date(if(rp.status = 'al_entry',rp.updated_at,null)) as al_entry,
397→            date(if(rp.status = 'archive', rp.updated_at, null)) as archive,
398→            ifnull(we.job_id, ifnull(oa.job_id, rp.job_id)) as real_job_id,
399→            rec.inputer_user_id,
400→            if(rec.status = 'success', 0,1) as is_repeat,
401→            rec.is_cooperation,
402→            max(si.positive_date) as in_service");
403→
404→        $resumes = RewardTemplatesMd::fromSub($subQuery, 'res')
405→            ->leftJoin('jobs', 'jobs.job_id', '=', 'res.real_job_id')
406→            ->leftJoin('job_template_map as jtm', function ($join) {
407→                $join->on('jtm.job_id', '=', 'res.real_job_id')
408→                    ->whereColumn('jtm.created_at', '<=', 'res.created_at')
409→                    ->whereColumn('jtm.end_time', '>', 'res.created_at');
410→            })->leftJoin('reward_templates as rt', function ($join) {
411→                $join->on('rt.template_id', '=', 'jtm.template_id')
412→                    ->whereColumn('rt.created_at', '<=', 'res.created_at')
413→                    ->whereColumn('rt.end_time', '>', 'res.created_at');
414→            })
415→            ->selectRaw('res.* , jobs.job_name, rt.rewards')->orderBy('created_at', 'desc')->get()->toArray();
416→
417→        $cooperation = RewardTemplatesMd::where('template_name', 'cooperation==')->where('is_on', 1)->selectRaw('rewards , created_at, end_time')->get()->toArray();
418→
419→        $users = userInfo();
420→
421→        $resumes = array_map(function ($item) use ($cooperation, $users) {
422→            $user = $users[$item['inputer_user_id']] ?? ['nickname' => '暂未分配'];
423→            $item['inputer_user_name'] = $user['nickname'];
424→            unset($item['inputer_user_id']);
425→
426→            if ($item['is_cooperation']) { // 业务合作的需要修改奖金
427→                foreach ($cooperation as $coop) { // 考虑过二分查找之类的，但是感觉数据量不大，没啥必要
428→                    if ($coop['created_at'] <= $item['created_at'] && $coop['end_time'] > $item['created_at']) {
429→                        $item['rewards'] = $coop['rewards'];
430→                        break;
431→                    }
432→                }
433→            }
434→            return $item;
435→        }, $resumes);
436→
437→        return $this->responseJsonSuccess(['resumes' => $resumes]);
438→    }
