501→    public function activeReceiveNeeds(array $input): array
502→    {
503→        $needs = $input['recruitment_needs_id'];
504→        $success = [];
505→        $failed = [];
506→        foreach ($needs as $needsId) {
507→            /** @var RecruitmentNeedsMd $recruitmentNeeds */
508→            $recruitmentNeeds = RecruitmentNeedsMd::where('id', $needsId)->first();
509→            if ($recruitmentNeeds == null) {
510→                $failed[] = $needsId;
511→                continue;
512→            }
513→            // 需求未开始或者已结束
514→            if (in_array($recruitmentNeeds->needs_status, [RecruitmentNeedsMd::NEEDS_STATUS_END, RecruitmentNeedsMd::NEEDS_STATUS_NOT_START])) {
515→                $failed[] = $needsId;
516→                continue;
517→            }
518→            // 需求未通过
519→            if ($recruitmentNeeds->approval_status != RecruitmentNeedsMd::APPROVAL_STATUS_ADMIN_APPROVED) {
520→                $failed[] = $needsId;
521→                continue;
522→            }
523→            RecruitmentNeedsHrMapMd::updateOrCreate([
524→                'recruitment_needs_id' => $needsId,
525→                'hr_user_id' => AuthRecord::user()->user_id,
526→                'receive_type' => RecruitmentNeedsHrMapMd::RECEIVE_TYPE_ACTIVE,
527→            ]);
528→            if ($recruitmentNeeds->is_received != 1) {
529→                $recruitmentNeeds->is_received = 1;
530→                $recruitmentNeeds->save();
531→            }
532→            $success[] = $needsId;
533→        }
534→
535→        return [
536→            'success' => $success,
537→            'failed' => $failed,
538→        ];
539→    }
