436→                ->select('rec.created_at', 'rec.status', 'jobs.job_id', 'jobs.job_name')
437→                ->get()->toArray() ?? [];
438→            $resume['onboarding_review'] = $onboardingReview[$resume['id']] ?? [];
439→            $resume['job_volunteer'] = [];
440→            if (!empty($resume['expect_job_ids'])) {
